+  // Avoid incorrectly folding unsigned comparisons against all-ones.
+  // For example, "icmp ult i8 X, -1" is true for X in [0, 254], and false only for X == 255.
+  // We must not fold this to a constant unless we can prove LHS cannot be below RHS.
+  if (Pred == ICmpInst::ICMP_ULT && C->isAllOnesValue()) {
