+      // However, for C == all-ones, this is only safe if LHS_All starts at C.
+      APInt AllOnes = *C;
+      // Check if LHS is known to be always >= C (i.e., no value less than C).
+      if (!LHS_All.contains(ConstantRange::getNonEmpty(AllOnes, AllOnes + 1))) {
+        // If we can't prove LHS is exactly C, do not simplify.
+        return nullptr;
+      }
+      // If LHS is provably equal to C (range width == 1 at C), then ULT is false.
+      if (LHS_All.getLower() == AllOnes && LHS_All.getUpper() == AllOnes + 1)
+        return ConstantInt::getFalse(ITy);
+      // Otherwise, be conservative.
+      return nullptr;
+    }
+    // If we know nothing (full set), do not fold.
+    return nullptr;
+  }
+
